static PyObject* FNePyStruct_Box2D_RichCmp(FNePyStruct_Box2D* InSelf, PyObject* InOther, int InOp)
{
	switch (InOp)
	{
		case Py_EQ:
			return FNePyStruct_Box2D___eq__(InSelf, InOther);
		case Py_NE:
			return FNePyStruct_Box2D___ne__(InSelf, InOther);
		default:
			break;
	}

	return PyErr_Format(PyExc_NotImplementedError, "this kind of compare is not implemented by Box2D");
}

bool NePyStructPropSet_Box2D(const FStructProperty* InStructProp, FNePyStructBase* InSelf, void* InBuffer)
{
	if (FNePyStruct_Box2D* PyObj = NePyStructCheck_Box2D(InSelf))
	{
		InStructProp->Struct->CopyScriptStruct(InBuffer, PyObj->Value);
		return true;
	}
	return false;
}

FNePyStructBase* NePyStructPropGet_Box2D(const FStructProperty* InStructProp, const void* InBuffer)
{
	PyTypeObject* PyType = &FNePyStructType_Box2D;
	FNePyStruct_Box2D* PyObj = (FNePyStruct_Box2D*)PyType->tp_alloc(PyType, 0);
#if NEPY_ENABLE_STRUCT_DEEP_ACCESS
	PyObj->Value = (FBox2D*)InBuffer;
	PyObj->SelfCreatedValue = false;
#else
	PyObj->Value = (FBox2D*)FMemory::Malloc(sizeof(FBox2D), alignof(FBox2D));
	NePyBase::EnsureCopyToStructSafely<FBox2D>(InStructProp, PyObj->Value);
	InStructProp->Struct->CopyScriptStruct(PyObj->Value, InBuffer);
	PyObj->SelfCreatedValue = true;
#endif
	PyObj->PyOuter = nullptr;
	return PyObj;
}

PyTypeObject* NePyNePyWrappedStructInit_Box2D(const UScriptStruct* InScriptStruct, PyTypeObject* InPyBase)
{
	PyTypeObject* NePyStructType = &FNePyStructType_Box2D;
	TNePyStructBase<FBox2D>::InitTypeCommon(NePyStructType);
	NePyStructType->tp_init = (initproc)&FNePyStruct_Box2D_FBox2D;
	NePyStructType->tp_getset = FNePyStructType_Box2D_getset;
	NePyStructType->tp_methods = FNePyStructType_Box2D_methods;
	static PyNumberMethods PyNumber;
	PyNumber.nb_inplace_add = (binaryfunc)&FNePyStruct_Box2D___iadd__;
	PyNumber.nb_add = (binaryfunc)&FNePyStruct_Box2D___add__;
	NePyStructType->tp_as_number = &PyNumber;
	NePyStructType->tp_richcompare = (richcmpfunc)&FNePyStruct_Box2D_RichCmp;
	NePyStructType->tp_base = InPyBase;
	PyType_Ready(NePyStructType);

	if (InScriptStruct)
	{
		FNePyStructTypeInfo TypeInfo = {
			NePyStructType,
			ENePyTypeFlags::StaticPyType,
			(NePyStructPropSet)NePyStructPropSet_Box2D,
			(NePyStructPropGet)NePyStructPropGet_Box2D,
		};
		FNePyWrapperTypeRegistry::Get().RegisterWrappedStructType(InScriptStruct, TypeInfo);
	}

	return NePyStructType;
}

void NePyInitStruct_Box2D(PyObject* PyOuterModule)
{
	FNePyWrapperInitializer::Get().RegisterWrappedStructInitFunc(
		TBaseStructure<FBox2D>::Get(), NePyNePyWrappedStructInit_Box2D);
}

FNePyStruct_Box2D* NePyStructNew_Box2D(const FBox2D& InValue)
{
	PyTypeObject* PyType = &FNePyStructType_Box2D;
	FNePyStruct_Box2D* RetValue = (FNePyStruct_Box2D*)PyType->tp_alloc(PyType, 0);
	if (FNePyStruct_Box2D::Init(RetValue, nullptr, nullptr) < 0)
	{
		Py_DECREF(RetValue);
		return nullptr;
	}
	new(RetValue->Value) FBox2D(InValue);
	return RetValue;
}

FNePyStruct_Box2D* NePyStructCheck_Box2D(PyObject* InPyObj)
{
	if (InPyObj && PyObject_TypeCheck(InPyObj, &FNePyStructType_Box2D))
	{
		return (FNePyStruct_Box2D*)InPyObj;
	}
	return nullptr;
}

PyTypeObject* NePyStructGetType_Box2D()
{
	return &FNePyStructType_Box2D;
}

namespace NePyBase
{
	bool ToCpp(PyObject* InPyObj, FBox2D& OutVal)
	{
		if (FNePyStruct_Box2D* PyObj = NePyStructCheck_Box2D(InPyObj))
		{
			OutVal = *(FBox2D*)PyObj->Value;
			return true;
		}
		return false;
	}

	bool ToPy(const FBox2D& InVal, PyObject*& OutPyObj)
	{
		OutPyObj = NePyStructNew_Box2D(InVal);
		return true;
	}
}
